let marca = msg.payload.marca;
let modelo = msg.payload.modelo;
let sintoma = msg.payload.sintoma;

if (!marca || marca.trim() === "" ||
    !modelo || modelo.trim() === "" ||
    !sintoma || sintoma.trim() === "") {
    return null;
}

return msg;

// Verificar si tenemos datos de la IA
// Como restauramos los datos del formulario en el nodo anterior,
// la IA ahora está guardada en msg.payload.diagnostico_ia

var diagnostico = msg.payload.diagnostico_ia;

if (diagnostico && diagnostico.length > 0) {
    // Si hay diagnóstico, creamos el mensaje para la notificación
    var mensaje = "Diagnóstico IA Detectado:\n";
    diagnostico.forEach(function (d, i) {
        mensaje += (i + 1) + ". " + d.codigo_averia + " (" + d.probabilidad + "%)\n";
    });

    // Asignamos el mensaje al payload para que la notificación lo muestre
    msg.payload = mensaje;
    return msg;
} else {
    // Si no hay diagnóstico o falló algo
    msg.payload = "️ No se pudo obtener diagnóstico.";
    return msg;
}

