// 1. COPIA DE SEGURIDAD: Guardamos el formulario original para MongoDB
msg.datos_originales = msg.payload;

// 2. LISTA DE SÍNTOMAS (Deben coincidir con tu dataset de entrenamiento)
const sintomas = [
    "humo_negro", "humo_blanco", "humo_azul", "fuga_aceite", "fuga_refrigerante",
    "fuga_frenos", "fuga_combustible", "golpeteo_metalico", "silbido_turbo",
    "chirrido_correa", "clack_giro", "zumbido_rodamiento", "perdida_potencia",
    "tirones_aceleracion", "ralenti_inestable", "no_arranca", "se_cala_solo",
    "vibracion_volante", "pedal_freno_blando", "direccion_dura", "cambio_marchas_duro",
    "sobrecalentamiento", "aguja_temperatura_baja", "luz_check_engine", "luz_abs",
    "luz_bateria", "luz_aceite", "luz_airbag", "olor_quemado", "olor_combustible",
    "chirrido_frenos", "traqueteo_motor"
];

// 3. CONSTRUIR VECTOR BINARIO PARA LA IA
let vectorParaIA = {};
sintomas.forEach(s => {
    if (msg.payload[s] && msg.payload[s] !== "" && msg.payload[s] !== false) {
        vectorParaIA[s] = 1;
    } else {
        vectorParaIA[s] = 0;
    }
});

// 4. ENVIAR SOLO EL VECTOR AL SIGUIENTE NODO (HTTP Request)
msg.payload = vectorParaIA;

return msg;

// 1. Guardamos la respuesta que viene de Python
let respuestaIA = msg.payload;

// 2. RESTAURAMOS los datos originales del formulario (Cliente, Matrícula, etc.)
// Esto es clave para que MongoDB guarde el documento completo y no solo el vector numérico.
msg.payload = msg.datos_originales;

// 3. Añadimos el diagnóstico al documento que se guardará en Mongo
if (respuestaIA && respuestaIA.diagnostico) {
    msg.payload.diagnostico_ia = respuestaIA.diagnostico;
}

// 4. Preparamos texto para la pantalla del usuario (Dashboard)
if (respuestaIA && respuestaIA.diagnostico && respuestaIA.diagnostico.length > 0) {
    msg.ui_text = "🔍 Diagnóstico Probabilístico:\n" +
        respuestaIA.diagnostico.map((d, i) =>
            `${i + 1}. Código ${d.codigo_averia} (${d.probabilidad}%)`
        ).join('\n');
} else {
    msg.ui_text = "⚠️ No se detectaron averías claras.";
}

return msg;

// Cogemos la respuesta de la IA que viene de antes
var respuestaIA = msg.payload.diagnostico_ia;

// Si la IA devolvió algo, cogemos el primero (el más probable)
if (respuestaIA && respuestaIA.length > 0) {
    // Guardamos el código numérico que dio la IA (ej: 315)
    msg.codigo_averia_ia = respuestaIA[0].codigo_averia;
    msg.probabilidad = respuestaIA[0].probabilidad;

    // Preparamos la consulta para MongoDB. 
    // Buscamos en la colección 'averias' donde el campo 'codigo_averia' sea igual al que dio la IA
    msg.payload = { "codigo_averia": msg.codigo_averia_ia };
}

return msg;

// 1. Guardar la info de la avería que recibimos antes
var infoAveria = msg.info_averia_encontrada || {};

// 2. Obtener el código que predijo la IA
var codigoIA = msg.codigo_averia_ia;

// 3. Consultar MongoDB para obtener la pieza real
// Buscaremos en la colección 'equivalencias_completas'
msg.payload = { "codigo_averia": codigoIA };
msg.collection = "equivalencias_completas";

// Guardamos el código para usarlo después
msg.codigo_averia_consulta = codigoIA;

return msg;

// 1. RECUPERAR DATOS DE PASOS ANTERIORES
var infoAveria = msg.info_averia_encontrada || {};
var docPrecio = (msg.payload && msg.payload.length > 0) ? msg.payload[0] : {};
var datosFormulario = msg.datos_originales || {};
var dtcUsuario = datosFormulario.codigo_dtc || "";

// 2. CALCULAR PRESUPUESTO
var precioPieza = parseFloat(docPrecio.precio_base_eur) || 0;
var horasObra = parseFloat(docPrecio.horas_mano_obra) || 1.0;
var tarifaHora = 45;
var costeManoObra = horasObra * tarifaHora;
var totalPresupuesto = precioPieza + costeManoObra;
var proveedor = docPrecio.proveedor_preferente || "Multimarca";
var nombrePieza = msg.nombre_pieza_final || "Pieza Genérica";

// 3. TRADUCIR CÓDIGO IA A DTC ESTÁNDAR
var codigoIA = msg.codigo_averia_ia.toString();
var diccionarioDTC = {
    "315": "P0420",
    "316": "P0171",
    "118": "P0300",
    "202": "P0401",
    "205": "P0128"
};
var dtcPredicho = diccionarioDTC[codigoIA] || "Desconocido";

// 4. VALIDACIÓN ESCÁNER VIRTUAL
var estadoEscaneo = "";
var colorEstado = "";

if (dtcUsuario === "") {
    estadoEscaneo = "Sin código DTC introducido. Diagnóstico basado en síntomas.";
    colorEstado = "#ffc107";
} else if (dtcUsuario.toUpperCase().includes(dtcPredicho)) {
    estadoEscaneo = "✅ CONFIRMADO: El código del vehículo coincide con la IA.";
    colorEstado = "#28a745";
} else {
    estadoEscaneo = "⚠️ ATENCIÓN: El código del vehículo (" + dtcUsuario + ") difiere de la predicción (" + dtcPredicho + ").";
    colorEstado = "#dc3545";
}

// 5. GENERAR HTML PARA DASHBOARD
msg.payload = {
    html: `
    <div style="font-family: sans-serif; max-width: 800px;">
        <h3 style="color: #0056b3; border-bottom: 2px solid #0056b3; padding-bottom: 5px;">
            🔍 Diagnóstico Probabilístico
        </h3>
        <p><strong>Predicción IA:</strong> Código ${codigoIA} (Confianza: ${msg.probabilidad}%)</p>
        <p><strong>Avería Detectada:</strong> ${infoAveria.descripcion || "Análisis de síntomas completado"}</p>
        <hr>
        <div style="background-color: #f8f9fa; padding: 10px; border-radius: 5px; border-left: 5px solid ${colorEstado}; margin-bottom: 20px;">
            <strong>📡 Validación Escáner Virtual (OBD-II):</strong><br>
            <small>Usuario: <b>${dtcUsuario || "N/A"}</b> | Predicción IA: <b>${dtcPredicho}</b></small><br>
            <span style="font-weight:bold; color: ${colorEstado};">${estadoEscaneo}</span>
        </div>
        <h3 style="color: #28a745;">💰 Presupuesto Estimado de Reparación</h3>
        <p><strong>Pieza a Sustituir:</strong> ${nombrePieza}</p>
        <p><strong>Proveedor Recomendado:</strong> ${proveedor}</p>
        <table style="width: 100%; border-collapse: collapse; margin-bottom: 10px;">
            <tr style="background-color: #e9ecef;">
                <td style="padding: 8px; border: 1px solid #ddd;"><strong>Concepto</strong></td>
                <td style="padding: 8px; border: 1px solid #ddd; text-align: right;"><strong>Coste</strong></td>
            </tr>
            <tr>
                <td style="padding: 8px; border: 1px solid #ddd;">Pieza / Material</td>
                <td style="padding: 8px; border: 1px solid #ddd; text-align: right;">${precioPieza.toFixed(2)} €</td>
            </tr>
            <tr>
                <td style="padding: 8px; border: 1px solid #ddd;">Mano de Obra (${horasObra} h x ${tarifaHora} €/h)</td>
                <td style="padding: 8px; border: 1px solid #ddd; text-align: right;">${costeManoObra.toFixed(2)} €</td>
            </tr>
            <tr style="background-color: #d4edda; font-weight: bold; font-size: 1.1em;">
                <td style="padding: 8px; border: 1px solid #ddd;">TOTAL ESTIMADO</td>
                <td style="padding: 8px; border: 1px solid #ddd; text-align: right;">${totalPresupuesto.toFixed(2)} €</td>
            </tr>
        </table>
    </div>
    `
};

return msg;

// Recibimos el resultado de equivalencias (array de MongoDB)
var equivalencias = msg.payload;

if (equivalencias && equivalencias.length > 0) {
    var docEquivalencia = equivalencias[0];

    // Guardamos info técnica
    msg.info_tecnica = docEquivalencia;

    // Extraemos el NOMBRE REAL de la pieza
    var nombreReal = docEquivalencia.nombre_pieza;

    // Preparamos consulta para el siguiente MongoDB
    msg.payload = { "nombre_pieza": nombreReal };
    msg.nombre_pieza_definitiva = nombreReal;

    return msg;
} else {
    msg.payload = { "nombre_pieza": "Filtro de aceite" };
    msg.nombre_pieza_definitiva = "Pieza Genérica";
    return msg;
}
